// // This module implements a 4-bit binary counter that decrements on every clock cycle when enabled. When reset is activated, the counter should reset to zero.
module bin_counter(
    input               clk         ,   
    input               rst         ,
    input               enable      ,

    output  reg [3:0]   count
);

   //count
   always @(posedge clk or posedge rst) begin
       if(rst) begin
          count <= 0;
       end
       else if(enable) begin
          count <= count + 1;
       end
   end

endmodule
